module RefModule(
  input [1:0] address,
  input chipselect,
  input clk,
  input reset_n,
  input write_n,
  input [31:0] writedata,
  output reg [7:0] out_port,
  output reg [31:0] readdata
);reg [7:0] ctrl_in;
  wire clk_en;

  assign clk_en = 1;

  always @(posedge clk or negedge reset_n) begin
    if (~reset_n) begin
      ctrl_in <= 0;
    end else if (chipselect && ~write_n && address == 0) begin
      ctrl_in <= writedata[7:0];
    end
  end

  assign out_port = ctrl_in;
  assign readdata = {32'b0, ctrl_in};

endmodule
